class ResPQObj extends ResPQ {
  final BigInt nonce;
  final BigInt serverNonce;
  final Uint8List pq;
  final List<int> serverPublicKeyFingerprints;
  ResPQObj({required this.nonce, required this.serverNonce, required this.pq, required this.serverPublicKeyFingerprints, });
  @override
  int get crc => 0x5162463;
  @override
  void encode(TlEncoder e) {
    e.writeCrc(crc);
    e.writeRaw(bigIntToBytes(nonce, 16));
    e.writeRaw(bigIntToBytes(serverNonce, 16));
    e.writeBytes(pq);
    e.writeCrc(0x1cb5c415); e.writeInt32(serverPublicKeyFingerprints.length); for (final item in serverPublicKeyFingerprints) { e.writeInt64(item); }
  }
  static ResPQObj decode(TlDecoder d) {
    final nonce = bytesToBigInt(d.readRawBytes(16));
    final serverNonce = bytesToBigInt(d.readRawBytes(16));
    final pq = d.readBytes();
    final serverPublicKeyFingerprints = () { d.readCrc(); final len = d.readUint32(); return List.generate(len, (_) => d.readInt64()); }();
    return ResPQObj(nonce: nonce, serverNonce: serverNonce, pq: pq, serverPublicKeyFingerprints: serverPublicKeyFingerprints, );
  }
}

